import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.CxZWPeXl.js";const g=JSON.parse('{"title":"Evaluation & Feedback","description":"","frontmatter":{},"headers":[],"relativePath":"en/evaluation.md","filePath":"en/evaluation.md"}'),n={name:"en/evaluation.md"};function r(l,e,s,h,u,c){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="evaluation-feedback" tabindex="-1">Evaluation &amp; Feedback <a class="header-anchor" href="#evaluation-feedback" aria-label="Permalink to &quot;Evaluation &amp; Feedback&quot;">ŌĆŗ</a></h1><blockquote><p>Gain complete, specific professional feedback ranging from overall performance down to line-by-line analysis.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">ŌĆŗ</a></h2><p>After each practice session, AI Coach automatically generates a detailed evaluation report. It covers three levels of analysis:</p><ol><li><strong>Stage Evaluation</strong> ŌĆö Completion of sales stages and improvement suggestions.</li><li><strong>Comprehensive Review</strong> ŌĆö Overall performance summary and learning direction.</li><li><strong>Line-by-line Feedback</strong> ŌĆö Detailed analysis of each message.</li></ol><hr><h2 id="evaluation-report-interface" tabindex="-1">Evaluation Report Interface <a class="header-anchor" href="#evaluation-report-interface" aria-label="Permalink to &quot;Evaluation Report Interface&quot;">ŌĆŗ</a></h2><p>When you open a report (via the &quot;Review&quot; button in History), the layout is structured into key areas:</p><h3 id="toolbar-view-toggles" tabindex="-1">Toolbar &amp; View Toggles <a class="header-anchor" href="#toolbar-view-toggles" aria-label="Permalink to &quot;Toolbar &amp; View Toggles&quot;">ŌĆŗ</a></h3><ul><li><strong>Back Button:</strong> Return to the History list or Dashboard.</li><li><strong>Language Switcher:</strong> Change the report language.</li><li><strong>View Toggle Button:</strong> A prominent button to switch between two main views: <ul><li><strong>Comprehensive Review (Default)</strong>: View Stage Evaluation and the overall Comprehensive Review.</li><li><strong>View Sentence-by-sentence Evaluation (µ¬óĶ”¢ķĆÉÕÅźĶ®ĢÕā╣)</strong>: Deep dive into message-by-message analysis.</li></ul></li></ul><h3 id="persona-profile-context-right-panel" tabindex="-1">Persona Profile Context (Right Panel) <a class="header-anchor" href="#persona-profile-context-right-panel" aria-label="Permalink to &quot;Persona Profile Context (Right Panel)&quot;">ŌĆŗ</a></h3><p>Constantly visible to help you cross-reference the AI&#39;s critique with the customer&#39;s background:</p><ul><li><strong>MBTI Personality Type:</strong> e.g., INTJ (Architect). Crucial for understanding the user&#39;s decision-making style.</li><li><strong>Customer Details:</strong> Education, Marital Status, Income Bracket.</li><li><strong>Relationship:</strong> The current relationship context between the agent and customer.</li></ul><hr><h2 id="report-generation-process" tabindex="-1">Report Generation Process <a class="header-anchor" href="#report-generation-process" aria-label="Permalink to &quot;Report Generation Process&quot;">ŌĆŗ</a></h2><h3 id="trigger" tabindex="-1">Trigger <a class="header-anchor" href="#trigger" aria-label="Permalink to &quot;Trigger&quot;">ŌĆŗ</a></h3><p>When you click &quot;End Conversation&quot;, the system will: Close chat ŌåÆ Trigger 3 background tasks:</p><ul><li>Stage Evaluation Gen</li><li>Comprehensive Review Gen</li><li>Call Summary Gen</li></ul><blockquote><p>Note: Line-by-line feedback is generated in the background <em>during</em> the chat, right after each message.</p></blockquote><h3 id="ui-status" tabindex="-1">UI Status <a class="header-anchor" href="#ui-status" aria-label="Permalink to &quot;UI Status&quot;">ŌĆŗ</a></h3><p>Generation typically takes 30 seconds to 2 minutes.</p><hr><h2 id="_1-stage-evaluation" tabindex="-1">1. Stage Evaluation <a class="header-anchor" href="#_1-stage-evaluation" aria-label="Permalink to &quot;1. Stage Evaluation&quot;">ŌĆŗ</a></h2><p>The AI reviews the entire conversation at once against administrator-defined stage criteria to determine which sales stages you successfully reached.</p><h3 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">ŌĆŗ</a></h3><p>For each reached stage, an evaluation card provides analysis. If you failed to advance to the next stage, a &quot;Reason for Not Advancing&quot; section explains what you need to improve.</p><hr><h2 id="_2-comprehensive-review" tabindex="-1">2. Comprehensive Review <a class="header-anchor" href="#_2-comprehensive-review" aria-label="Permalink to &quot;2. Comprehensive Review&quot;">ŌĆŗ</a></h2><p>Unlike Stage Evaluation, the Comprehensive Review analyzes your performance from a soft-skills perspective: overall conversation quality, sales skills employed, relationship building, and professional knowledge displays.</p><h3 id="output-1" tabindex="-1">Output <a class="header-anchor" href="#output-1" aria-label="Permalink to &quot;Output&quot;">ŌĆŗ</a></h3><p>A Markdown-formatted report containing:</p><ul><li>Performance Overview</li><li>Strengths Review</li><li>Areas for Improvement</li><li>Actionable Next Steps</li></ul><hr><h2 id="_3-line-by-line-feedback" tabindex="-1">3. Line-by-line Feedback <a class="header-anchor" href="#_3-line-by-line-feedback" aria-label="Permalink to &quot;3. Line-by-line Feedback&quot;">ŌĆŗ</a></h2><p>The most granular level of feedback, analyzing the pros and cons of every single message you sent. Switch to this mode using the &quot;View Sentence-by-sentence Evaluation&quot; button.</p><h3 id="how-it-works" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it Works&quot;">ŌĆŗ</a></h3><p>This generates asynchronously during practice. When switching to the Line-by-line mode, you can review:</p><ul><li><strong>AI Inner Thoughts:</strong> What the customer was really thinking but didn&#39;t say aloud.</li><li>Detailed critiques of your messaging: Phrasing, stage effectiveness, and tonality.</li></ul><hr><h2 id="grading-the-ai-s-evaluation" tabindex="-1">Grading the AI&#39;s Evaluation <a class="header-anchor" href="#grading-the-ai-s-evaluation" aria-label="Permalink to &quot;Grading the AI&#39;s Evaluation&quot;">ŌĆŗ</a></h2><p>Below the Comprehensive Review and each Line-by-line item, you can Thumbs Up / Thumbs Down the AI&#39;s critique. This feedback helps improve the AI system iteratively.</p><h2 id="practice-tips" tabindex="-1">Practice Tips <a class="header-anchor" href="#practice-tips" aria-label="Permalink to &quot;Practice Tips&quot;">ŌĆŗ</a></h2><ol><li>Start with the <strong>Stage Evaluation</strong> to see how far you got.</li><li>Read the <strong>Reason for Not Advancing</strong> for immediate bottlenecks.</li><li>Check the <strong>Comprehensive Review</strong> for overall direction.</li><li>Dive into <strong>Line-by-line Feedback</strong> and read the <strong>AI Inner Thoughts</strong> to understand customer psychology better, cross-referencing their MBTI type.</li></ol>',43)])])}const p=a(n,[["render",r]]);export{g as __pageData,p as default};
